  ('pukao-0a2fc18c-moex-00143', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '2 1 2', '["對此消費者而言，X與X可以固定比例互相替代，2個X可替代3個X", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00144', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '2 1 2', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00145', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '如果長期而言，一家廠商的生產200單位產出的總成本是500元，生產300單位產出的總成本是600元，則我 們可以說在這兩個產量之間這家廠商的生產技術呈現：', '["規模報酬遞增，因為它的平均成本隨產量增加而提高", "規模報酬遞增，因為它的平均成本隨產量增加而降低", "規模報酬遞減，因為它的平均成本隨產量增加而提高", "規模報酬遞減，因為它的平均成本隨產量增加而降低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00146', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '拉拉漢堡賣40個漢堡時，其AC-AVC=3，當拉拉漢堡賣80個漢堡時，其AC-AVC為多少？', '["1.5", "6", "3", "2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00147', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '假設炸雞排是個完全競爭的市場，老王每天賣100片雞排，並賺取最大利潤，每片雞排的平均收益是60元， 平均總成本是35元。我們可推論老王的：', '["平均總成本和邊際成本相交處的數量大於100片", "平均變動成本和邊際成本相交處的數量大於100片", "平均變動成本和邊際成本相交處的數量少於100片", "他每天賺取6000元的利潤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00148', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '一家獨占廠商面對的需求線是P=100-Q，其中P和Q分別代表市場的價格與需求量。如果當這家廠商將價格 訂在60元時，它可以賺取最大利潤，此時它生產的邊際成本是多少？', '["60元", "50元", "40元", "20元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00149', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '一家自然獨占廠商面對的需求線是P=102-Q，其中P和Q分別代表市場的價格與需求量。如果當這家廠商的 邊際成本是2時，固定成本是1600。當政府採用平均成本訂價法管制這家廠商，並要求產量必須超過50單 位時，社會的無謂損失（deadweightloss）是多少？', '["200", "400", "800", "1600"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00150', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '雙占的研發賽局中，其報償如下：當A廠商與B廠商（下稱A、B）均研發時利潤分別為5萬元和3萬元；A、 B均不研發時利潤分別為15萬元和8萬元；A研發但B不研發時利潤分別為20萬元和1萬元；A不研發但B研 發時利潤分別為3萬元和12萬元。若B採取以牙還牙的策略，而A在第零期研發，則A在第一期與第二期該 如何做研發的選擇？', '["第一期研發，第二期研發", "第一期不研發，第二期研發", "第一期研發，第二期不研發", "第一期不研發，第二期不研發"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00151', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-112-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '在借貸市場中，利率是資本的價格。當政府對利息所得課稅時，對借貸市場均衡之影響，下列何者正確？', '["利息所得課稅政策會使得資本供給線左移，導致市場均衡利率提高", "利息所得課稅政策會使得資本需求線左移，導致市場均衡利率降低", "利息所得課稅政策會使得資本供給線右移，導致市場均衡利率下降", "利息所得課稅政策會使得資本需求線右移，導致市場均衡利率提高"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:10+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "417", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL)
